import{_ as a,o as b,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"四柱之枪-救世主","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/四柱之枪-救世主.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/四柱之枪-救世主.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/6.可升级/四柱之枪-救世主.md"};function d(o,e,_,l,i,c){return b(),t("div",null,[...e[0]||(e[0]=[r("h1",{id:"四柱之枪-救世主",tabindex:"-1"},[p("四柱之枪-救世主 "),r("a",{class:"header-anchor",href:"#四柱之枪-救世主","aria-label":'Permalink to "四柱之枪-救世主"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),n('<h1 id="四柱之枪-救世主-1" tabindex="-1">四柱之枪-救世主 <a class="header-anchor" href="#四柱之枪-救世主-1" aria-label="Permalink to &quot;四柱之枪-救世主&quot;">​</a></h1><p>四柱之枪—救世主<br> 魔幻本质<br> 概述：安息绝杰·玛温消失后遗留下来的武器，外表是一根金色的长枪，枪身刻有四颗鲜红的宝珠。传说被救世主刺穿的人，都会静止不动，陷入彻底的死寂。</p><p>本武器为逐级购买，若无特殊说明，高等级时保留低等级效果，特性叠加</p><p>D+500<br> 分类：长枪<br> 武器伤害：4L<br> 武器特性：【格挡4】【破甲4】【双手】【长柄】<br> 伤害类型：物理-穿刺<br> 特性：【四柱】<br> 【四柱】：在用本武器攻击时，可以以一个自由动作在身体周围幻化出另外三把四柱之枪与你一起协同攻击，在攻击时可以攻击你攻击主目标外触及范围内的另外三个不同的目标。由于只是幻化，所以仍然视为一把武器，视为同一次攻击。</p><p>【四柱之枪—救世主】</p><p>C+1000<br> 分类：长枪<br> 武器伤害：12L<br> 武器特性：【格挡4】【破甲4】【双手】【长柄】【9加骰】<br> 伤害类型：物理-穿刺 特性：【安神】<br> 【安神】：如果攻击命中，则敌方对本次攻击的伤害值为dc进行一次意志豁免，豁免失败会让敌方陷入短暂的困眠，这会使其获得C级心灵来源的【耗竭】效果，【耗竭】状态会导致目标损失2AP，持续一轮<br> B+2500<br> 分类：长枪<br> 武器伤害：20L<br> 武器特性：【格挡4】【破甲4】【双手】【长柄】【8加骰】<br> 伤害类型：物理-穿刺<br> 特性：【散播福音】【安神-提升】<br> 【散播福音】：以该武器进行的攻击视为具有B级时空来源的传送攻击效果，并且获得基于使用者传奇决心*2+2点破魔，若该破防属性结算后仍有剩余则转化为攻击上的士气加值。<br> 【安神】：C级提供的【耗竭】效果提升为B级，豁免失败后，减少的AP提升为4AP。</p><p>【四柱之枪—救世主】<br> A+4000<br> 分类：长枪<br> 武器伤害：32L+1附加成功<br> 武器特性：【格挡4】【破甲4】【双手】【长柄】【8加骰】<br> 伤害类型：物理-穿刺<br> 特性：【散播福音提升】【安神-提升】<br> 【散播福音】：将安息的福音散播于整个世界吧，当你以该武器进行攻击时，触及距离视为等同于自身敏感范围，将武器递出，便会如拥有A级时空来源传送攻击般从身后刺出，令忙碌的心脏享受安息。<br> 【安神-提升】：纵享安息吧……该特性B级提供的【耗竭】效果提升为A级，豁免失败后，减少的AP提升为8AP，安息的力量会模糊他们对于自身力量的感受，忘却存世的烦恼，令他们无法以自我意志抗衡；针对攻击伤害作为dc额外进行一次意志豁免，豁免失败者将无法使用意志力，无法施展低于A级的任何技艺，这是一个A级别、时空来源的【扼魂】效果。</p><p>====================<br> 如果你拥有C级及以上的训练【安息的试炼】，在将该武器逐升至B时你可以选择将其升级变更为以下形态，一经选择无法更改。<br> 【温柔之花—安息】<br> B+2000<br> 在安息绝杰消失之后，你经过众人的推举成为了安息的继承者，代替安息的绝杰继续履行安息的试炼，但这真的是你期望的安息吗？<br> 分类：长枪<br> 武器伤害：0L+7附加成功<br> 武器特性：【格挡2】【破魔3】【双手】【长柄】<br> 伤害类型：无<br> 描述：本武器的名称变更为【温柔之花—安息】，外形变为两枚碧绿色的戒指，需佩戴在双手才能使用。本武器的攻击方式是：佩戴者使用语言和肢体行与对方交流、谈话，用温柔方式对待对方来尝试让对方打开心扉，让对方相信只要温柔对待他人，明天会变的更好，从而失去对我方的敌意。本武器仍然正常视为长枪，具备长枪的基础特性。</p><p>使用该武器时，你的攻击视为时空来源的B级传送攻击，在使用该武器进行攻击时，若你在当前回合使用了【安息】魔力的基础用法，则可以使得这次攻击额外附带伤害等量影响心灵来源的精神束缚点数，意志豁免；如果承受攻击的目标至少因此承受1点精神束缚点数，则目标在攻击上承受使用者传奇决心*4点士气减值，持续一轮。<br> 每轮一次，你可以以一个花招动作唤醒自身拥有的纹章，若如此做，每拥有一个可以获得【纹章】效果的C级或更高级技艺（差价升级则视为同一个），都将使得自身下一次进行的攻击额外具有1点附加成功，至多以此获得6点附加成功。</p><p>【温柔之花—安息】<br> A+？<br> 描述：在更新新的十杰卡包之前，你无法购买该武器的A级版本。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const f=a(s,[["render",d]]);export{A as __pageData,f as default};
